def caesar_cipher(s: String, shift: Int) -> String:
    var result = String("")
    var sh = ((shift % 26) + 26) % 26
    for cp in s.codepoints():
        var c = Int(cp)
        if c >= 65 and c <= 90:
            c = (c - 65 + sh) % 26 + 65
        elif c >= 97 and c <= 122:
            c = (c - 97 + sh) % 26 + 97
        result += chr(c)
    return result

def rot13(s: String) -> String:
    var result = String("")
    for cp in s.codepoints():
        var c = Int(cp)
        if c >= 65 and c <= 90:
            c = (c - 65 + 13) % 26 + 65
        elif c >= 97 and c <= 122:
            c = (c - 97 + 13) % 26 + 97
        result += chr(c)
    return result

def is_anagram(a: String, b: String) -> Int:
    var ca = List[Int]()
    for _ in range(26):
        ca.append(0)
    for cp in a.codepoints():
        var c = Int(cp)
        if c >= 65 and c <= 90:
            c += 32
        if c >= 97 and c <= 122:
            ca[c - 97] += 1
    for cp in b.codepoints():
        var c = Int(cp)
        if c >= 65 and c <= 90:
            c += 32
        if c >= 97 and c <= 122:
            ca[c - 97] -= 1
    for i in range(26):
        if ca[i] != 0:
            return 0
    return 1

def count_digits(s: String) -> Int:
    var count = 0
    for cp in s.codepoints():
        var c = Int(cp)
        if c >= 48 and c <= 57:
            count += 1
    return count

