def sum_of_digits_in_string(s: String) -> Int:
    var total = 0
    for cp in s.codepoints():
        var c = Int(cp)
        if c >= 48 and c <= 57:
            total += c - 48
    return total

def longest_run_char(s: String) -> Int:
    var n = s.byte_length()
    if n == 0:
        return 0
    var best = 1
    var cur = 1
    for i in range(1, n):
        if String(s[byte=i]) == String(s[byte=i - 1]):
            cur += 1
            if cur > best:
                best = cur
        else:
            cur = 1
    return best

def capitalize_words(s: String) -> String:
    var result = String("")
    var start = 1
    for cp in s.codepoints():
        var c = Int(cp)
        if c == 32:
            start = 1
            result += chr(c)
        else:
            if start == 1 and c >= 97 and c <= 122:
                c -= 32
            start = 0
            result += chr(c)
    return result

