def strip_spaces(s: String) -> String:
    var n = s.byte_length()
    var i = 0
    var j = n - 1
    while i < n and String(s[byte=i]) == " ":
        i += 1
    while j >= i and String(s[byte=j]) == " ":
        j -= 1
    var result = String("")
    for k in range(i, j + 1):
        result += String(s[byte=k])
    return result

def replace_char(s: String, frm: String, to: String) -> String:
    var result = String("")
    for cp in s.codepoint_slices():
        if String(cp) == frm:
            result += to
        else:
            result += String(cp)
    return result

def is_numeric(s: String) -> Int:
    var n = s.byte_length()
    if n == 0:
        return 0
    for cp in s.codepoints():
        var c = Int(cp)
        if c < 48 or c > 57:
            return 0
    return 1

def hamming_str(a: String, b: String) -> Int:
    var n = a.byte_length()
    var count = 0
    for i in range(n):
        if String(a[byte=i]) != String(b[byte=i]):
            count += 1
    return count

def count_uppercase(s: String) -> Int:
    var count = 0
    for cp in s.codepoints():
        var c = Int(cp)
        if c >= 65 and c <= 90:
            count += 1
    return count

def first_unique_char_index(s: String) -> Int:
    var freq = List[Int]()
    for _ in range(256):
        freq.append(0)
    for cp in s.codepoints():
        freq[Int(cp)] += 1
    var idx = 0
    for cp in s.codepoints():
        if freq[Int(cp)] == 1:
            return idx
        idx += 1
    return -1

def repeat_string(s: String, n: Int) -> String:
    var result = String("")
    for _ in range(n):
        result += s
    return result

def swap_case(s: String) -> String:
    var result = String("")
    for cp in s.codepoints():
        var c = Int(cp)
        if c >= 65 and c <= 90:
            c += 32
        elif c >= 97 and c <= 122:
            c -= 32
        result += chr(c)
    return result

def remove_vowels(s: String) -> String:
    var result = String("")
    for cp in s.codepoints():
        var c = Int(cp)
        var l = c
        if l >= 65 and l <= 90:
            l += 32
        if l == 97 or l == 101 or l == 105 or l == 111 or l == 117:
            continue
        result += chr(c)
    return result

def is_subsequence(a: String, b: String) -> Int:
    var i = 0
    var n = a.byte_length()
    var m = b.byte_length()
    var j = 0
    while j < m and i < n:
        if String(a[byte=i]) == String(b[byte=j]):
            i += 1
        j += 1
    if i == n:
        return 1
    return 0

def count_substring_overlap(s: String, sub: String) -> Int:
    var n = s.byte_length()
    var m = sub.byte_length()
    if m == 0:
        return 0
    var count = 0
    for i in range(n - m + 1):
        var ok = 1
        for k in range(m):
            if String(s[byte=i + k]) != String(sub[byte=k]):
                ok = 0
                break
        if ok == 1:
            count += 1
    return count

def levenshtein(a: String, b: String) -> Int:
    var n = a.byte_length()
    var m = b.byte_length()
    var prev = List[Int]()
    var cur = List[Int]()
    for j in range(m + 1):
        prev.append(j)
        cur.append(0)
    for i in range(1, n + 1):
        cur[0] = i
        for j in range(1, m + 1):
            var cost = 1
            if String(a[byte=i - 1]) == String(b[byte=j - 1]):
                cost = 0
            var d = prev[j] + 1
            var ins = cur[j - 1] + 1
            var sb = prev[j - 1] + cost
            var mn = d
            if ins < mn:
                mn = ins
            if sb < mn:
                mn = sb
            cur[j] = mn
        for j in range(m + 1):
            prev[j] = cur[j]
    return prev[m]
